# !/usr/bin/env python3

from flask import Flask, request, jsonify, send_file
import io
import pickle


app = Flask(__name__)
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 ** 2 # 16MB


class ModelServingAPI():
    def __init__(self):
        self._modelMap = {}
    
    @classmethod
    def getInstance(cls):
        if 'INSTANCE' not in cls.__dict__:
            cls.INSTANCE = cls()
        
        return cls.INSTANCE
        
    def createModel(self, modelName, modelFileContents):        
        modelObj = pickle.loads(modelFileContents)
        
        self._modelMap[modelName] = modelObj
    
    @classmethod
    def getModelNames(cls):
        instance = cls.getInstance()
        return [key for key in instance._modelMap]
        
    def serveModelByName(self, modelName):
        return send_file(io.BytesIO(pickle.dumps(self._modelMap[modelName])), attachment_filename=f'{modelName}_123456789.p', mimetype='application/octet-stream')
    
    
    def serveModelByModelFileContents(self, modelFileContent):
        modelObj = pickle.loads(modelFileContent)
        
        for model in self._modelMap:
            if self._modelMap[model] is not modelObj and self._modelMap[model].__class__.__name__ == modelObj.__class__.__name__:
                self._modelMap.pop(model, None)
        
        self._modelMap['model'] = modelObj


@app.route('/models', methods=['GET'])
def getModels():
    instance = ModelServingAPI()
    return jsonify({'status': 'success', 'data': {
        'modelNames':  instance.getModelNames()    
    }})


@app.route('/model-files/upload/<modelName>', methods=['POST'])
def postModelFile(modelName): 
    instance = ModelServingAPI().getInstance()
    
    if modelName not in instance._modelMap:        
        fileContent = request.files['file'].read()
        
        instance.createModel(modelName, fileContent)
    else:
        raise Exception('Model already exists')


@app.route('/models/<modelName>', methods=['GET'])
def getModelByName(modelName):
    return ModelServingAPI().serveModelByName(modelName).data
    

@app.route('/models/upload', methods=['POST'])
def postModelByFileContents():
    instance = ModelServingAPI()
    
    fileContent = request.files['file'].read()
    
    instance.serveModelByModelFileContents(fileContent)


if __name__ == '__main__':
   app.run(port=5012, debug=True)